mapper.select:
SELECT *
FROM communication_record
WHERE enterprise_id = #{enterpriseId}

    AND application_id = #{applicationId}


    AND job_id = #{jobId}


    AND student_id = #{studentId}


    AND communication_type = #{communicationType}


    AND is_read = #{isRead}

ORDER BY created_time DESC, id DESC

SELECT *
FROM communication_record
WHERE enterprise_id = #{enterpriseId}
  AND id = #{id}
LIMIT 1

SELECT *
FROM communication_record
WHERE student_id = #{studentId}
  AND id = #{id}
LIMIT 1

SELECT cr.id AS recordId, cr.application_id AS applicationId, ja.application_no AS applicationNo, cr.job_id AS jobId, COALESCE(JSON_UNQUOTE(JSON_EXTRACT(ja.job_snapshot_json, '$.jobTitle')), jp.job_title) AS jobTitle, ja.enterprise_id AS enterpriseId, COALESCE(JSON_UNQUOTE(JSON_EXTRACT(ja.enterprise_snapshot_json, '$.enterpriseName')), eu.company_name) AS enterpriseName, cr.communication_type AS communicationType, cr.communication_subject AS communicationSubject, cr.communication_content AS communicationContent, cr.is_read AS isRead, cr.need_student_confirm AS needStudentConfirm, cr.student_confirmed AS studentConfirmed, cr.interview_time AS interviewTime, cr.interview_address AS interviewAddress, cr.created_time AS createdTime FROM communication_record cr LEFT JOIN job_application ja ON ja.id = cr.application_id LEFT JOIN job_posting jp ON jp.id = cr.job_id LEFT JOIN education_user_db.enterprises eu ON eu.id = ja.enterprise_id WHERE cr.student_id = #{studentId}
AND cr.application_id = #{applicationId}
AND cr.is_read = #{isRead}
ORDER BY cr.created_time DESC, cr.id DESC

SELECT cr.id AS recordId, cr.application_id AS applicationId, ja.application_no AS applicationNo, cr.job_id AS jobId, COALESCE(JSON_UNQUOTE(JSON_EXTRACT(ja.job_snapshot_json, '$.jobTitle')), jp.job_title) AS jobTitle, cr.student_id AS studentId, COALESCE(u.real_name, u.nickname) AS studentName, cr.communication_type AS communicationType, cr.communication_subject AS communicationSubject, cr.communication_content AS communicationContent, cr.need_student_confirm AS needStudentConfirm, cr.student_confirmed AS studentConfirmed, cr.is_read AS isRead, cr.read_time AS readTime, cr.created_time AS createdTime FROM communication_record cr LEFT JOIN job_application ja ON ja.id = cr.application_id LEFT JOIN job_posting jp ON jp.id = cr.job_id LEFT JOIN education_user_db.students s ON s.id = cr.student_id LEFT JOIN education_user_db.users u ON u.id = s.user_id WHERE cr.enterprise_id = #{enterpriseId}
AND cr.application_id = #{applicationId}
AND cr.job_id = #{jobId}
AND cr.student_id = #{studentId}
AND cr.communication_type = #{communicationType}
AND cr.is_read = #{isRead}
ORDER BY cr.created_time DESC, cr.id DESC

