UPDATE communication_record
SET is_read = 1,
    read_time = #{readTime},
    updated_time = #{readTime}
WHERE enterprise_id = #{enterpriseId}
  AND id = #{id}
  AND (is_read = 0 OR is_read IS NULL)

UPDATE communication_record
SET is_read = 1,
    read_time = #{readTime},
    updated_time = #{readTime}
WHERE student_id = #{studentId}
  AND id = #{id}
  AND (is_read = 0 OR is_read IS NULL)

UPDATE communication_record
SET is_read = 1,
    read_time = #{readTime},
    updated_time = #{readTime}
WHERE student_id = #{studentId}
  AND application_id = #{applicationId}
  AND (is_read = 0 OR is_read IS NULL)

